question:
What is the output of the following code snippet?

```cpp
#include <iostream>
class Base {
public:
    virtual void print() { std::cout << "Base"; }
};
class Derived : public Base {
public:
    void print() override { std::cout << "Derived"; }
};
int main() {
    Base* b1 = new Base();
    Base* b2 = new Derived();
    b1->print();
    b2->print();
    delete b1;
    delete b2;
    return 0;
}
```
